+import {IgnoreTypes} from '../utils/ignore-types';
+import {Options, RuleType} from '../rules';
+import RuleBuilder, {DropdownOptionBuilder, ExampleBuilder, OptionBuilderBase} from './rule-builder';
+
+type LinkStyleValue = 'no-change' | 'markdown' | 'wiki';
+
+class LinkStyleOptions implements Options {
+  linkStyle: LinkStyleValue = 'no-change';
+  imageStyle: LinkStyleValue = 'no-change';
+}
+
+/** Convert the small, deliberately supported subset of Obsidian and Markdown links. */
+@RuleBuilder.register
+export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.link-style.name',
+      descriptionKey: 'rules.link-style.description',
+      type: RuleType.CONTENT,
+      ruleIgnoreTypes: [
+        IgnoreTypes.yaml, IgnoreTypes.code, IgnoreTypes.inlineCode, IgnoreTypes.math,
+        IgnoreTypes.inlineMath, IgnoreTypes.html, IgnoreTypes.templaterCommand,
+        IgnoreTypes.obsidianMultiLineComments, IgnoreTypes.table,
+      ],
+    });
+  }
+
+  get OptionsClass(): new () => LinkStyleOptions {
+    return LinkStyleOptions;
+  }
+
+  apply(text: string, options: LinkStyleOptions): string {
+    if (options.linkStyle === 'markdown' || options.imageStyle === 'markdown') {
+      text = wikiToMarkdown(text, options);
+    }
+    if (options.linkStyle === 'wiki' || options.imageStyle === 'wiki') {
+      text = markdownToWiki(text, options);
+    }
+    return text;
+  }
+
+  get exampleBuilders(): ExampleBuilder<LinkStyleOptions>[] {
+    return [
+      new ExampleBuilder({
+        description: 'Convert wiki links and embeds to Markdown',
+        before: '[[page#heading]] and ![[image.png|300x200]]',
+        after: '[page > heading](page#heading) and ![image.png](image.png)',
+        options: {linkStyle: 'markdown', imageStyle: 'markdown'},
+      }),
+      new ExampleBuilder({
+        description: 'Convert Markdown links and images to wiki syntax',
+        before: '[display](page) and ![alt](image.png)',
+        after: '[[page|display]] and ![[image.png|alt]]',
+        options: {linkStyle: 'wiki', imageStyle: 'wiki'},
+      }),
+    ];
+  }
+
+  get optionBuilders(): OptionBuilderBase<LinkStyleOptions>[] {
+    return [
+      new DropdownOptionBuilder<LinkStyleOptions, LinkStyleValue>({
+        OptionsClass: LinkStyleOptions,
+        nameKey: 'rules.link-style.link-style.name',
+        descriptionKey: 'rules.link-style.link-style.description',
+        optionsKey: 'linkStyle',
+        records: styleRecords(),
+      }),
+      new DropdownOptionBuilder<LinkStyleOptions, LinkStyleValue>({
+        OptionsClass: LinkStyleOptions,
+        nameKey: 'rules.link-style.image-style.name',
+        descriptionKey: 'rules.link-style.image-style.description',
+        optionsKey: 'imageStyle',
+        records: styleRecords(),
+      }),
+    ];
+  }
+}
+
+function styleRecords(): {value: LinkStyleValue, description: string}[] {
+  return [
+    {value: 'no-change', description: 'Do not change this kind of link'},
+    {value: 'markdown', description: 'Use Markdown link syntax'},
+    {value: 'wiki', description: 'Use Obsidian wiki link syntax'},
+  ];
+}
+
+function wikiToMarkdown(text: string, options: LinkStyleOptions): string {
+  return text.replace(/(!)?\\[\\[([^\\]\
]+)\\]\\]/g, (whole, embed: string, contents: string) => {
+    const image = embed === '!';
+    if ((image ? options.imageStyle : options.linkStyle) !== 'markdown') return whole;
+
+    const separator = contents.indexOf('|');
+    const target = separator < 0 ? contents : contents.slice(0, separator);
+    if (!target) return whole;
+    let display = separator < 0 ? defaultDisplay(target) : contents.slice(separator + 1);
+    if (image && /^(\\d+|\\d+x\\d+)$/.test(display)) display = target;
+    return image ? `![${display}](${target})` : `[${display}](${target})`;
+  });
+}
+
+function markdownToWiki(text: string, options: LinkStyleOptions): string {
+  let output = '';
+  let index = 0;
+  while (index < text.length) {
+    const candidate = parseMarkdownLink(text, index);
+    if (!candidate) {
+      output += text[index++];
+      continue;
+    }
+    const style = candidate.image ? options.imageStyle : options.linkStyle;
+    if (style !== 'wiki' || candidate.target.includes('://')) {
+      output += candidate.source;
+    } else {
+      const display = candidate.label;
+      const omitted = !candidate.image && (display === candidate.target || display === defaultDisplay(candidate.target));
+      const imageDisplay = candidate.image && (display === '' || display === candidate.target);
+      output += candidate.image
+        ? `![[${candidate.target}${imageDisplay ? '' : `|${display}`}]]`
+        : `[[${candidate.target}${omitted ? '' : `|${display}`}]]`;
+    }
+    index = candidate.end;
+  }
+  return output;
+}
+
+type MarkdownLink = {image: boolean, label: string, target: string, source: string, end: number};
+
+function parseMarkdownLink(text: string, start: number): MarkdownLink | null {
+  const image = text[start] === '!';
+  const bracketStart = image ? start + 1 : start;
+  if (text[bracketStart] !== '[' || (!image && text[start - 1] === '!')) return null;
+  let cursor = bracketStart + 1;
+  let depth = 1;
+  for (; cursor < text.length && depth; cursor++) {
+    if (text[cursor] === '\\\') {
+      cursor++;
+    } else if (text[cursor] === '[') {
+      depth++;
+    } else if (text[cursor] === ']') {
+      depth--;
+    }
+  }
+  if (depth || text[cursor] !== '(') return null;
+  const labelRaw = text.slice(bracketStart + 1, cursor - 1);
+  if (labelRaw.includes('\
')) return null;
+
+  const parenStart = cursor++;
+  depth = 1;
+  for (; cursor < text.length && depth; cursor++) {
+    if (text[cursor] === '\\\') {
+      cursor++;
+    } else if (text[cursor] === '(') {
+      depth++;
+    } else if (text[cursor] === ')') {
+      depth--;
+    }
+  }
+  if (depth) return null;
+  const area = text.slice(parenStart + 1, cursor - 1);
+  if (area.includes('\
')) return null;
+  const target = parseDestination(area);
+  if (target === null || target === '') return null;
+  return {image, label: unescapeMarkdown(labelRaw), target, source: text.slice(start, cursor), end: cursor};
+}
+
+function parseDestination(area: string): string | null {
+  const trimmed = area.trim();
+  if (trimmed.startsWith('<')) {
+    let close = -1;
+    for (let i = 1; i < trimmed.length; i++) {
+      if (trimmed[i] === '\\\') i++;
+      else if (trimmed[i] === '>') { close = i; break; }
+    }
+    if (close < 0 || trimmed.slice(close + 1).trim() !== '') return null;
+    return unescapeMarkdown(trimmed.slice(1, close));
+  }
+  let depth = 0;
+  let space = -1;
+  for (let i = 0; i < trimmed.length; i++) {
+    if (trimmed[i] === '\\\') { i++; continue; }
+    if (trimmed[i] === '(') depth++;
+    else if (trimmed[i] === ')') depth--;
+    else if (/\\s/.test(trimmed[i]) && depth === 0) { space = i; break; }
+  }
+  if (space >= 0 && trimmed.slice(space).trim() !== '') return null; // a title is present
+  return unescapeMarkdown(space < 0 ? trimmed : trimmed.slice(0, space));
+}
+
+function unescapeMarkdown(value: string): string {
+  return value.replace(/\\\\(.)/g, '$1');
+}
+
+function defaultDisplay(target: string): string {
+  const heading = target.indexOf('#');
+  if (heading < 0) return target;
+  const page = target.slice(0, heading);
+  const section = target.slice(heading + 1);
+  return page ? `${page} > ${section}` : section;
+}
